mapper.update:
UPDATE tb_checklist_category
SET category_name = #{categoryName}, sort_order = #{sortOrder}, modified_at = GETDATE()
WHERE id = #{id}

mapper.delete:
DELETE FROM tb_checklist_inspection_result WHERE item_id IN (
    SELECT i.id FROM tb_checklist_item i
    JOIN tb_checklist_category c ON i.category_id = c.id
    WHERE c.template_id = #{templateId}
)

mapper.select:
SELECT MAX(i.item_no) FROM tb_checklist_item i
JOIN tb_checklist_category c ON i.category_id = c.id
WHERE c.template_id = #{templateId}
